create_issue "Implement extract_wasm_offset from error messages" "Implement \`extract_wasm_offset(error_msg: &str) -> Option<u64>\` finding hex offsets in error strings.\n\n**Acceptance criteria:**\n- Correctly extracts offset from Soroban/Wasmi errors\n- Returns None when absent\n- Unit tests with sample strings" "core,diagnostics"

echo "Issues 71-80 created..."

